const rows = $input.all();
const statements = [];
const now = new Date();
const year = now.getFullYear();

for (const row of rows) {
  const data = row.json;
  const metric = (data['Metric'] || '').trim();
  if (!metric) continue;
  const target = (data['Target'] || '').replace(/'/g, "''");

  for (const [key, val] of Object.entries(data)) {
    if (key === 'Metric' || key === 'Target' || !val) continue;
    // Match MMDD format columns
    const match = key.match(/^(\d{2})(\d{2})$/);
    if (!match) continue;
    const month = parseInt(match[1]);
    const day = parseInt(match[2]);
    // Handle year rollover (Nov/Dec columns in Jan-May)
    let dateYear = year;
    if (month >= 11 && now.getMonth() < 5) dateYear = year - 1;
    const weekDate = dateYear + '-' + String(month).padStart(2, '0') + '-' + String(day).padStart(2, '0');
    const numVal = parseFloat(String(val).replace(/[^0-9.-]/g, ''));
    if (isNaN(numVal)) continue;

    const safeMet = metric.replace(/'/g, "''");
    const sql = "INSERT INTO scorecard_financials (metric_name, week_date, value, target_value) VALUES ('" + safeMet + "', '" + weekDate + "', " + numVal + ", '" + target + "') ON CONFLICT (metric_name, week_date) DO UPDATE SET value = EXCLUDED.value, target_value = EXCLUDED.target_value, captured_at = NOW();";
    statements.push({ json: { sql } });
  }
}
return statements.length > 0 ? statements : [{ json: { sql: 'SELECT 1' } }];

